#!/bin/bash
set -eux  # Exit on error, print commands

# Remove the generated common certificate material at the certs/ root, leaving the .cnf inputs and
# the scripts. This does NOT touch certs/configuration, whose certificates are not regenerated by
# makecerts.sh. Run this before a full regeneration of the common certificates when you want a
# clean slate.
find . -maxdepth 1 -type f \( \
    -name '*.pem' -o \
    -name '*.der' -o \
    -name '*.p12' -o \
    -name '*.jks' -o \
    -name '*.bks' -o \
    -name '*.csr' -o \
    -name '*.srl' \
\) -exec rm -fv {} +
